const Q_GEOGRAPHY_1994=[{"id": "objective>Geography>1994>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following scales would allow the greatest amount of detail on a map?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1: 20</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1: 50</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1: 500</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1: 2,500</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">1: 20 would allow the greatest amount of detail on a map, since it is the greatest of all the ratios given</div>", "topic": "PRATICAL GEOGRAPHY I : SCALE AND MEASUREMENT DISTANCES"}, {"id": "objective>Geography>1994>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The captain of a ship in the mid sea observed that it was local noon as he was listening to 08.00 hrs BBC world news. On which longitude was his ship?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">60°E</div>", "<div style=\"font-family:Cambria;font-size:17px;\">60°W</div>", "<div style=\"font-family:Cambria;font-size:17px;\">120°E</div>", "<div style=\"font-family:Cambria;font-size:17px;\">120°W</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">If your chronometer is duly set to GMT, that means you are four hours east of the zero meridian at local noon. The captain was listening to the broadcast at 08:00 hrs i.e 8:00am. <br/> Time difference = 12:00 noon - 8:00am=4hours <br/> convert time difference to longitude <br/> recall 1hour =15<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span> <br/> 4hours=x <br/> x=4 * 15 =60<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span> <br/> Hence, the captain is 60<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>E</div>", "topic": "PRATICAL GEOGRAPHY II : THE EARTH AS A PLANET"}, {"id": "objective>Geography>1994>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A map drawn to a scale of 1: 180,000 is reduced three times. What is the scale of the new map?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1: 60,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1: 90,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1: 360,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1: 540,000</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When a map is reduced, the representative fraction become bigger. <br/> scale of the new map=scale of the old map * reduction factor <br/> =1/180000 *1/3=1/540000=1: 540,000</div>", "topic": "PRATICAL GEOGRAPHY I : SCALE AND MEASUREMENT DISTANCES"}, {"id": "objective>Geography>1994>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Sedimentary rocks are easily recognized in the field because they?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">form round hills</div>", "<div style=\"font-family:Cambria;font-size:17px;\">are faulted</div>", "<div style=\"font-family:Cambria;font-size:17px;\">form vertical columns</div>", "<div style=\"font-family:Cambria;font-size:17px;\">occur in layers</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">One of the characteristics of sedimentary rocks is the fact that they occur in layers or strata i.e they are stratified rocks. This makes them easily recognizable in fields.</div>", "topic": "PRATICAL GEOGRAPHY II : ROCKS"}, {"id": "objective>Geography>1994>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">At which of the following latitudes would you expect more than 24 hours of continuous sunshine or darkness at a particular time of the year?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">40°N and S</div>", "<div style=\"font-family:Cambria;font-size:17px;\">50°N and S</div>", "<div style=\"font-family:Cambria;font-size:17px;\">60°N and S</div>", "<div style=\"font-family:Cambria;font-size:17px;\">70°N and S</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">At the artic circle (66<span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">1</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">2 </span>), the sun never rises and there is darkness for the whole day(December 22).Also, at the artic circle, the sun never sets by June 21 and there is a complete twenty-four hour period of continuous daylight and this region(artic circle) at this time is called the The land of the midnight sun. The sun is overhead at the Tropic of cancer and no part is in darkness.Hence, at 70<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>N and S we should expect more than 24 hours of continuous sunshine or darkness at a particular time of the year.</div>", "topic": "PRATICAL GEOGRAPHY II : THE EARTH AS A PLANET"}, {"id": "objective>Geography>1994>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following sets of rocks is organically formed?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Rock salt, breccia and conglometerate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Clay, mudstone and sandstone</div>", "<div style=\"font-family:Cambria;font-size:17px;\">peat, chalk and limestone</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Girt, coal and shale</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Organically formed sedimentary rocks are rocks formed from the remains of living organisms. When sedimentary rocks are formed from the remains of animals like corals or shellfish, such rocks are called calcareous rocks e.g limestone and chalk. But when sedimentary rocks are formed from the remains of vegetable matter such as swamps and forest, they are called carbonaceous rock e.g coal,peat,lignite etc.</div>", "topic": "PRATICAL GEOGRAPHY II : ROCKS"}, {"id": "objective>Geography>1994>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of these sets of rivers enter the sea through estuaries?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">The Thames, Zaire and Plate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The Plate, Ganges and Columbia</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The Nile, Rhine and st. Lawrence</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The Zarie, Thames and Niger</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The River Thames flows into the North sea near Tilbury, Essex and Gravesend, Kent, via the Thames Estuary.The Zaire River also known as the Congo river is the second longest river in Africa. The Zaire's estuary begins at Matadi, flowing to the northwest, west and southwest before draining into the Atlantic Ocean. The river Plate(Rio de la plata) is formed as the confluence of the Parana and Uruguay rivers and results in a pretty wide estuary with Montevideo(Uruguay). It empties into the Atlantic ocean and forms a funnel-shaped indentation on the southeastern coastline of south America  </div>", "topic": "PRATICAL GEOGRAPHY II : WATER BODIES"}, {"id": "objective>Geography>1994>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following landforms originates from aeolian erosion?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Wadi</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Deflation hollow</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> Sand dune</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Playa</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Aeoline erosion is the wind's ability to shape the surface of the earth. Deflation is an action of wind/aeolian erosion. Deflation results in the lowering of the land's surface to form large depression called deflation hollows.</div>", "topic": "PRATICAL GEOGRAPHY II : LANDFORMS"}, {"id": "objective>Geography>1994>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The circulation of ocean currents is?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"> clockwise both in the north and southern hemispheres</div>", "<div style=\"font-family:Cambria;font-size:17px;\">anti-clockwise both in the southern hemispheres</div>", "<div style=\"font-family:Cambria;font-size:17px;\">anti-clockwise in the northern hemisphere and clockwise both in the southern hemispheres</div>", "<div style=\"font-family:Cambria;font-size:17px;\">clockwise in the northern hemisphere and clockwise both in the southern hemispheres</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Ocean currents are influenced by the rotation of the Earth called Coriolis Effect which causes currents to flow clockwise in the nothern hemisphere and anticlockwise in the southern hemisphere </div>", "topic": "PRATICAL GEOGRAPHY II : WATER BODIES"}, {"id": "objective>Geography>1994>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Seasons are recognized with in the tropics primarily on the basis of?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">air masses</div>", "<div style=\"font-family:Cambria;font-size:17px;\">temperature</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rainfall</div>", "<div style=\"font-family:Cambria;font-size:17px;\">evaporation</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Seasonal differences in the tropics are usually determined by rainfall patterns, such that the dry season is called \"summer\" and the wet season is \"winter\" </div>", "topic": "PRATICAL GEOGRAPHY II : WEATHER AND CLIMATE"}, {"id": "objective>Geography>1994>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A major feature of the tropical continental climates is the?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">relatively low annual range of temperature</div>", "<div style=\"font-family:Cambria;font-size:17px;\">regular and reliable rainfall</div>", "<div style=\"font-family:Cambria;font-size:17px;\">excess of evaporation over rainfall</div>", "<div style=\"font-family:Cambria;font-size:17px;\">excess of rainfall over evaporation</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the tropical continental climate, there is little or no rainfall. Areas which experience tropical continental climate experience high temperatures during the year.As a result of high temperature, the rate of evaporation is far greater than that of rainfall.</div>", "topic": "PRATICAL GEOGRAPHY II : WEATHER AND CLIMATE"}, {"id": "objective>Geography>1994>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The most dominant pair of active factors affecting plants growth is?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">soil and fauna</div>", "<div style=\"font-family:Cambria;font-size:17px;\">climate and soil</div>", "<div style=\"font-family:Cambria;font-size:17px;\">climate and topography</div>", "<div style=\"font-family:Cambria;font-size:17px;\">topography and man</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The soil is the thin surface of the uppermost layer of the earth's crust on which plants grow. The physical and biological components of a soil play an important role in a plants growth.Also, the atmospheric condition of a region over a long period of time also affects  plants' growth.</div>", "topic": "PRATICAL GEOGRAPHY II : ENVIRONMENTAL INTERACTION"}, {"id": "objective>Geography>1994>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The major constituents of a typical soil are?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">gravel, sand, silt and clay</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mineral matter, organic matter, air and water</div>", "<div style=\"font-family:Cambria;font-size:17px;\">stone, mineral matter, pore spaces and micro-organism</div>", "<div style=\"font-family:Cambria;font-size:17px;\">calcium, magnesium, potassium amd sodium</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The soil is made up of five components which are; inorganic or mineral matter, organic matter,soil water,soil air and living organisms. Mineral or inorganic matter, organic matter,soil water and soil air are collectively referred as physical components of the soil while living organisms are referred to as biological components of the soil</div>", "topic": "PRATICAL GEOGRAPHY II : SOILS"}, {"id": "objective>Geography>1994>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In a humid areas, farmers add lime to the soil to? </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">facilitate the absorption of nutrients</div>", "<div style=\"font-family:Cambria;font-size:17px;\">encourage the development of green leaves</div>", "<div style=\"font-family:Cambria;font-size:17px;\">act as fertilizer</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> reduce acidity</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The soil pH refers to the degree of alkalinity or acidity in the soil. Soil acidity is caused as a result of the presence of abundance of hydrogen ions(H<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span>). To reduce soil acidity farmers add lime to the soil.</div>", "topic": "PRATICAL GEOGRAPHY II : SOILS"}, {"id": "objective>Geography>1994>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following trees is most suitable for pulp and paper production?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Obeche</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ebony</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Spruce</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Mahogany</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Spruce and fir trees are the best choice when making paper. They are moderate-to-fast-growing trees, making them more renewable than some of the other choices.Spruce and true fir trees also require little energy to make into pulp.</div>", "topic": "PRATICAL GEOGRAPHY II : VEGETATION"}, {"id": "objective>Geography>1994>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Urban centres are best distinguished from rural, settlements by their?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">morphology and location</div>", "<div style=\"font-family:Cambria;font-size:17px;\">population and function</div>", "<div style=\"font-family:Cambria;font-size:17px;\">site and function</div>", "<div style=\"font-family:Cambria;font-size:17px;\">morphology and demography</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Urban centres are relatively large, densely populated settlements which is mainly involved in secondary and tertiary activities such as manufacturing, construction and many other service oriented jobs while rural settlements are relatively small area with socially homogenous people that know one another very well. They are normally involved in primary activities such as farming, fishing and lumbering.Hence, urban centres are distinguished from rural settlements by their population and function</div>", "topic": "HUMAN GEOGRAPHY : SETTLEMENT"}, {"id": "objective>Geography>1994>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A sharp decrease in the population of herbivores in an ecosystem is likely to lead to?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">an increase in the amount of plant cover</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a decrease in the population of rodents</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> an increase inthe population of rodents</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a decrease in the population of saprophytes</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Herbivores are plant-consuming animals i.e they feed on green leaves. Examples of herbivores are cattle, sheep, cow,goat etc.Hence, a sharp decrease in the population of herbivores in an ecosystem is likely to lead to an increase in the amount of plant cover.</div>", "topic": "HUMAN GEOGRAPHY : POPULATION"}, {"id": "objective>Geography>1994>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The population size of any place is best determined by?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the level of industrialization and the standard of living of the people</div>", "<div style=\"font-family:Cambria;font-size:17px;\">natural change and migration</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> census and vital registeration</div>", "<div style=\"font-family:Cambria;font-size:17px;\">its migration and employment indices</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The movement of people from one geographical area to another, involving permanent or temporary residence i.e migration decreases population of the source geographical area and increases the population of the destination region.</div>", "topic": "HUMAN GEOGRAPHY : POPULATION"}, {"id": "objective>Geography>1994>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A broad-based population pyramid is composed mainly of?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"> old dependants</div>", "<div style=\"font-family:Cambria;font-size:17px;\">young dependants</div>", "<div style=\"font-family:Cambria;font-size:17px;\">active inhabitants</div>", "<div style=\"font-family:Cambria;font-size:17px;\">more males than females</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A broad-based population pyramid indicates that people in the younger age categories make up  a relatively large proportion  of the population and a narrow or pointed top indicates that older people make up relatively small proportion of the population</div>", "topic": "HUMAN GEOGRAPHY : POPULATION"}, {"id": "objective>Geography>1994>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In which of the following regions is the high population density due to industrial development?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">China</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The Nile Valley</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Java</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The Rhur Valley</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Rhur valley is a polycentric urban area in North Rhine-Westphalia, Germany. With a population density of 2800km<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span> and a population of over 5million, it is the largest urban area in Germany. Its industrial development is due to its high population density. </div>", "topic": "HUMAN GEOGRAPHY : POPULATION"}, {"id": "objective>Geography>1994>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following sets of cities has been developed specially as the seat of government?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Abuja, Chicago and Brasilia</div>", "<div style=\"font-family:Cambria;font-size:17px;\">New Delhi, Abuja and Calcutta</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Chicago, New Delhi, and Abuja</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Canberra, Brasilia and Abuja</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Canberra, Brasilia and Abuja are the capital cities of Australia, Brazil and Nigeria respectively. Hence, these three cities are the seat of governments of their respective countries. </div>", "topic": "HUMAN GEOGRAPHY : SETTLEMENT"}, {"id": "objective>Geography>1994>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Dispersed rural settlements are most likely to be found in areas with?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"> abundant agriculture land and good surface drainage</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> limited agricultural land and poor surface drainage</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a large agricultural population and restricted accessibility</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a small agricultural population and poor surface drainage</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In a dispersed or scattered settlement, there is presence of an abundant intensively tilled agricultural land with a good surface drainage</div>", "topic": "HUMAN GEOGRAPHY : SETTLEMENT"}, {"id": "objective>Geography>1994>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The most important factors that have promoted urbanization in Africa during the 20th century are?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">industrial development, decolonization and modern transport development</div>", "<div style=\"font-family:Cambria;font-size:17px;\">modern transport development, commerce and industrialization</div>", "<div style=\"font-family:Cambria;font-size:17px;\">trade, improved rural conditions and industrialization</div>", "<div style=\"font-family:Cambria;font-size:17px;\">decolonization, poor rural conditions and commercialization</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Trade with foreign countries, improvement in rural conditions and the widespread development of industries in Africa have promoted urbanization.</div>", "topic": "HUMAN GEOGRAPHY : SETTLEMENT"}, {"id": "objective>Geography>1994>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Subsistence farming is characterized by?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">dominance of cash crops, low capital input and dependence on simple tools</div>", "<div style=\"font-family:Cambria;font-size:17px;\">dominance of food crops, small holdings anfd family labour</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Dependence on family labour, small holdings and market orientation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Dependence on simple tools, labour intensity and high capital input</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In Subsistence farming <br/> -familylabour is used <br/> -Food crops like maize,cassava, yam etc are mainly grown</div>", "topic": "HUMAN GEOGRAPHY : SELECTED ECONOMIC ACTIVITIES"}, {"id": "objective>Geography>1994>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The major areas of mixed farming in the world are also areas of?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">sparse population with low arable crop productions</div>", "<div style=\"font-family:Cambria;font-size:17px;\">dense population with a high percentage of farms</div>", "<div style=\"font-family:Cambria;font-size:17px;\">dense population and a large number of urban centres</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sparse population and dispersed rural settlements</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Mixed farming is a type of farming which involves both the growing of crops and raising of livestock. It is practised in countries such as India,Malaysia,China,Russia etc, these countries are densely populated and possess a large  number of urban centres.  <br/> Mixed farming is a type of farming which involves both the growing of crops as well as the raising of livestock. These areas are typically densely populated with a high percentage of farms. This is because mixed farming requires a significant amount of labor and resources, which is more likely to be found in densely populated areas.</div>", "topic": "HUMAN GEOGRAPHY : SELECTED ECONOMIC ACTIVITIES"}, {"id": "objective>Geography>1994>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Specialized cultivation of grapes is associated with?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Mediterrarean regions</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cool temperates climates</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> montane climates</div>", "<div style=\"font-family:Cambria;font-size:17px;\">monsoon regions</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Human activities such as orchard farming and viticulture i.e the cultivation of grape fruits is practised in the meditteranean region</div>", "topic": "HUMAN GEOGRAPHY : SELECTED ECONOMIC ACTIVITIES"}, {"id": "objective>Geography>1994>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Plantation agriculture may be described as a system characterized by?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">small-scale production , heavy mechnanization and industrial crops</div>", "<div style=\"font-family:Cambria;font-size:17px;\">heavy mechanization, food importation and subsistence crops</div>", "<div style=\"font-family:Cambria;font-size:17px;\">large-scale production, monoculture and centre management</div>", "<div style=\"font-family:Cambria;font-size:17px;\">labour specialization, market dependence and poor capital base</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Plantation agriculture requires commercial cultivation in which products are mainly for sale. It usually involves the cultivation of one crop i.e moncropping and also requires a large capital investment</div>", "topic": "REGIONAL GEOGRAPHY : PLANTATION AGRICULTURE IN WEST AND EAST AFRICA"}, {"id": "objective>Geography>1994>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A type of industry that is carried on usually at or near the residence and based largely on native skills and simple technology is referred to as a?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">local industry</div>", "<div style=\"font-family:Cambria;font-size:17px;\">light industry</div>", "<div style=\"font-family:Cambria;font-size:17px;\">consumers industry</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cottage industry</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Local craft or cottage industries are those type of industries that depend mainly on raw materials obtained from their immediate locality. They use simple tools and their work is of high artistic quality</div>", "topic": "HUMAN GEOGRAPHY : SELECTED ECONOMIC ACTIVITIES"}, {"id": "objective>Geography>1994>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A major limiting factor to the development of industries in the developing countries is?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">low level of capital formation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">high population growth rate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">shortage of raw materials</div>", "<div style=\"font-family:Cambria;font-size:17px;\">unfavorable climates</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In developing countries, there is insufficiency of capital and access to finance or loan which is very difficult without possession of valuable collateral securities</div>", "topic": "HUMAN GEOGRAPHY : SELECTED ECONOMIC ACTIVITIES"}, {"id": "objective>Geography>1994>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In which of the following countries have many railway lines been closed down as a result of a decline in their competitiveness?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">South Africa</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Australia</div>", "<div style=\"font-family:Cambria;font-size:17px;\">U.S.A</div>", "<div style=\"font-family:Cambria;font-size:17px;\">India</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In Australia, the rail services are not reliable. The double handling at each end (at the terminals) just increases the cost and damages.</div>", "topic": "HUMAN GEOGRAPHY : SELECTED ECONOMIC ACTIVITIES"}, {"id": "objective>Geography>1994>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The list of exports from Japan to Nigeria is likely to include?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">motor vehicles, television sets and coal</div>", "<div style=\"font-family:Cambria;font-size:17px;\">wrist watches, chemicals and crude oil</div>", "<div style=\"font-family:Cambria;font-size:17px;\">motor vehicles, cameras and industrial machines</div>", "<div style=\"font-family:Cambria;font-size:17px;\">television sets, iron ore and computers</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Nigeria imports goods such as Vehicles,cameras and industrial machines from Japan through the Cape Route and the Lagos-Osaka(Japan) seaport is used</div>", "topic": "REGIONAL GEOGRAPHY : BROAD OUTLINE OF NIGERIA"}, {"id": "objective>Geography>1994>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The main hydrological centre in Nigeria is the?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Jos Plateau</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Western Uplands</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Biu Plateau</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Eastern Highlands</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The rocks of the Jos-Bukuru plateau in the North central Nigeria is characterized by hydrological centres with high hydrological and hydrogeological significance.</div>", "topic": "REGIONAL GEOGRAPHY : BROAD OUTLINE OF NIGERIA"}, {"id": "objective>Geography>1994>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The highest landforms in Nigeria are developed on?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">sandstones</div>", "<div style=\"font-family:Cambria;font-size:17px;\">granites</div>", "<div style=\"font-family:Cambria;font-size:17px;\">basalts</div>", "<div style=\"font-family:Cambria;font-size:17px;\">shales</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The highest notable landforms in Nigeria include the Adamawa plateau,Mambilla plateau,Jos plateau,Rivers Niger and Benue,Udi Hills etc. They are developed on granites which are found in all the states of Nigeria.</div>", "topic": "REGIONAL GEOGRAPHY : GEOGRAPHICAL REGIONS OF NIGERIA"}, {"id": "objective>Geography>1994>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A system of continuous cultivation based on intensive use of manure is widely practiced in the?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"> Kano close-settled zone</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Chad Basin</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> Niger Valley</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Jos area</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Organic manure has been the single most important agricultural input for the smallholder farmer in the Kano close settled zone</div>", "topic": "REGIONAL GEOGRAPHY : IRRIGATION AGRICULTURE IN THE NILE AND NIGER BASIN"}, {"id": "objective>Geography>1994>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The veldt is a temperate grassland found in?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">South Africa</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Australia</div>", "<div style=\"font-family:Cambria;font-size:17px;\">South America</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Eurasia</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The grasses in the temperate grassland have different names in different areas where they are found. These include:The veldt of South Africa, the Downs of Australia, The Pampas of Argentina,The Prairies of North America and The Steppe of Central Europeans Russia.</div>", "topic": "HUMAN GEOGRAPHY : SETTLEMENT"}, {"id": "objective>Geography>1994>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An Africa country seeking to reduce unemployment through industrialization will most likely encourage?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">capital - intensive industries</div>", "<div style=\"font-family:Cambria;font-size:17px;\">technology - intensive industries</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> small- scale industries</div>", "<div style=\"font-family:Cambria;font-size:17px;\">labour - intensive industries</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">To solve the problem of unemployment through industrialization, industries which require wokers in high quantity is required.In other words labour-intensive industries will reduce the problem of unemployment. </div>", "topic": "HUMAN GEOGRAPHY : SELECTED ECONOMIC ACTIVITIES"}, {"id": "objective>Geography>1994>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Agricultural productivity is low in Tropical Africa because of?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">sparse population and shortage of labour</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> poor soil and unfavourable climate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">low technology and land fragmentation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">low demand and lack of credit facilities</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Lack of technological know-how is a problem of agricultural productivity in Tropical Africa.Also,land fragmentation causes inefficient allocation of labour and capital leading to increased costs of production and with the hindering of agricultural modernization</div>", "topic": "REGIONAL GEOGRAPHY : AFRICA ON BROAD OUTLINE"}, {"id": "objective>Geography>1994>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The greatest problem facing lumbering in Tropical Africa is that the?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">trees are often buttressed at the base</div>", "<div style=\"font-family:Cambria;font-size:17px;\">trees do not grow in pure stands</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> further expansion of saw- mill is not viable</div>", "<div style=\"font-family:Cambria;font-size:17px;\">demand is low</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In Tropical Africa, most trees are not in pure stands. This mean that trees are of different species and this makes felling difficult</div>", "topic": "REGIONAL GEOGRAPHY : LUMBERING IN EQUATORIAL AFRICA"}, {"id": "objective>Geography>1994>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Three land-locked countries in West Africa are?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Republic of Benin, Mauritania and Niger</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Togo, Ghana and Chad</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Mali, Burkina Faso and Niger</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Mali, Chad and Senegal</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">landlocked countries refer to those countries which do not have an access or boundaries with the coast or oceans.Examples of landlocked countries are Mali, Burkina Faso,chad,Central Africa republc,Uganda,Rwand,Niger etc <br/>  </div>", "topic": "REGIONAL GEOGRAPHY : GEOGRAPHICAL REGIONS OF NIGERIA"}, {"id": "objective>Geography>1994>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the chart below to answer the question <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> If the total population of the city is 500,000. What is the population of ward4? </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">150,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">125,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">100,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">75,000</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The population of Ward 4 = 54/360 * 500000 = 75,000</div>", "topic": "HUMAN GEOGRAPHY : POPULATION"}, {"id": "objective>Geography>1994>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the chart below to answer the question <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> An alternative graphic method that can be used to depict the same information is the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">dot map</div>", "<div style=\"font-family:Cambria;font-size:17px;\">proportional circle</div>", "<div style=\"font-family:Cambria;font-size:17px;\">divided rectangle</div>", "<div style=\"font-family:Cambria;font-size:17px;\">choropeth</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The choropeth map refers to a diagrammatic representation of certain figures, information or data in form of densities.In other words, different types of shadings or densities are used to represent the data provided on a particular issue e.g the population of states in a country</div>", "topic": "PRATICAL GEOGRAPHY I : MAP READING AND INTERPRETATION"}, {"id": "objective>Geography>1994>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the map below to answer the question <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The area shaded and marked Q is well known for its </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">oil palm forest</div>", "<div style=\"font-family:Cambria;font-size:17px;\">crdue oil</div>", "<div style=\"font-family:Cambria;font-size:17px;\">swamp rice</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ginger plantation</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The shaded region shows the major oil palm producing states. They include: Enugu,Imo,Ondo,Edo,Cross River,Delta, Akwa Ibom, Ekiti,Bayelsa,Rivers,Anambra,Oyo,Abia, Edo and Ogun state </div>", "topic": "REGIONAL GEOGRAPHY : PLANTATION AGRICULTURE IN WEST AND EAST AFRICA"}, {"id": "objective>Geography>1994>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> Use the map below to answer the question <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> Which important mineral is exploited at the place marked X?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">tin ore</div>", "<div style=\"font-family:Cambria;font-size:17px;\">iron ore</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> limestone</div>", "<div style=\"font-family:Cambria;font-size:17px;\">gold</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">At the point X, iron ore such as cassiterite,limestone,zircon, columbite,haematite and magnetite are being exploited in great quantities </div>", "topic": "PRATICAL GEOGRAPHY II : MINERAL EXPLOITATION"}, {"id": "objective>Geography>1994>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the graph below to answer the question <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> What climatic type is illustrated in the graph? </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Montane</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Equatorial</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Mediterranean</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Monsoon</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The monsoon climates has winds that are not steady but pulsating in nature. The monsoon is known for its uncertainty </div>", "topic": "PRATICAL GEOGRAPHY II : WEATHER AND CLIMATE"}, {"id": "objective>Geography>1994>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the graph below to answer the question <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The annual range of temperature as shown in the graph is approximately</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">4 <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C</div>", "<div style=\"font-family:Cambria;font-size:17px;\">8<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C <br/> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">24<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C <br/> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">28<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C <br/> </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Annual range of temperature=Highest temperature - Lowest temperature <br/> 9<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span> -5<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>=4<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C</div>", "topic": "PRATICAL GEOGRAPHY I : MAP READING AND INTERPRETATION"}, {"id": "objective>Geography>1994>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the map below to answer the question <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The length of the main road from Robo junction to Oseb junction is approximately </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"> 6.5km</div>", "<div style=\"font-family:Cambria;font-size:17px;\">7.5km</div>", "<div style=\"font-family:Cambria;font-size:17px;\">8.5km</div>", "<div style=\"font-family:Cambria;font-size:17px;\">9.5km</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">From the diagram, the distance is approximately 6.5km</div>", "topic": "PRATICAL GEOGRAPHY I : MAP READING AND INTERPRETATION"}, {"id": "objective>Geography>1994>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the map below to answer the question <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The relative relief of the area is slightly above</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">75m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">105m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">485m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">575m</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">From the diagram, the relative relief is slightly above 575m </div>", "topic": "PRATICAL GEOGRAPHY I : MAP READING AND INTERPRETATION"}, {"id": "objective>Geography>1994>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the map below to answer the question <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The major human activity in the area is probably?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Farming</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Fishing</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Lumbering</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ranching</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Due to the abundance of farmlands in the region, farming is most likely to be practised</div>", "topic": "PRATICAL GEOGRAPHY II : LANDFORMS"}, {"id": "objective>Geography>1994>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the map below to answer the question <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The feature marked Y is best described as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Valley</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Spur</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Gap</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Pass</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The feature marked Y is a pass because it separates two highlands at a lower level</div>", "topic": "PRATICAL GEOGRAPHY I : MAP READING AND INTERPRETATION"}, {"id": "objective>Geography>1994>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the map below to answer the question <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The roads in the area run mainly along</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Steep slopes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Hilltops</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Gentle slopes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Watersheds</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The roads in the area run in a highland area which separates the headstreams of rivers flowing in different directions but rising from the same mountainous source. So, the roads run along watersheds</div>", "topic": "PRATICAL GEOGRAPHY I : MAP READING AND INTERPRETATION"}];
